import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void mixedTransactions() {
        // balances: 100, 50, 250, -50, 0 → max=250
        assertEquals(250, new Solution().maxRunningBalance(new int[]{100, -50, 200, -300, 50}));
    }

    @Test
    void allDebits() {
        // balances: -10, -30, -60 → max=-10
        assertEquals(-10, new Solution().maxRunningBalance(new int[]{-10, -20, -30}));
    }

    @Test
    void zeroMove() {
        // balances: 0 → max=0
        assertEquals(0, new Solution().maxRunningBalance(new int[]{0}));
    }

    @Test
    void empty() {
        assertEquals(0, new Solution().maxRunningBalance(new int[]{}));
    }

    @Test
    void allCredits() {
        // balances: 5, 15, 30 → max=30
        assertEquals(30, new Solution().maxRunningBalance(new int[]{5, 10, 15}));
    }
}
